1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { resolve } from '$app/paths';
4		import { page } from '$app/stores';
5		import { createClient } from '$lib/gql/client';
6		import { PLUGIN_DISPATCH_MUTATION, PLUGINS_LIST_QUERY } from '$lib/gql/feat008';
7		import { subscribeWorkerProgress } from '$lib/gql/subscriptions';
8		import ConfirmDialog from '$lib/components/ConfirmDialog.svelte';
9		import Tooltip from '$lib/components/Tooltip.svelte';
10		import { onDestroy } from 'svelte';
11		import { SvelteMap, SvelteSet } from 'svelte/reactivity';
12		import {
13			AlertCircle,
14			Download,
15			ExternalLink,
16			Loader2,
17			PackageCheck,
18			RefreshCw
19		} from 'lucide-svelte';
20	
21		type Scope = 'global' | 'project';
22		type PluginAction = 'install' | 'update';
23		type PluginInfo = PageData['plugins'][number];
24	
25		interface DispatchResult {
26			pluginDispatch: {
27				id: string;
28				state: string;
29				action: PluginAction;
30			};
31		}
32	
33		interface PluginsListResult {
34			pluginsList: PluginInfo[];
35		}
36	
37		interface PluginSnapshot {
38			status: string;
39			installedVersion: string | null;
40		}
41	
42		interface FailureState {
43			workerId: string;
44			action: PluginAction;
45		}
46	
47		let { data }: { data: PageData } = $props();
48	
49		// Local list is refreshed after plugin workers finish.
50		// svelte-ignore state_referenced_locally
51		const initialPlugins = data.plugins;
52		let plugins = $state<PluginInfo[]>(initialPlugins);
53		let installingPlugin = $state<PluginInfo | null>(null);
54		let installOpen = $state(false);
55		let installScope = $state<Scope>('global');
56		const dispatchingPlugins = new SvelteSet<string>();
57		const inFlightWorkers = new SvelteMap<string, string>();
58		const inFlightActions = new SvelteMap<string, PluginAction>();
59		const dispatchSnapshots = new SvelteMap<string, PluginSnapshot>();
60		const workerFailures = new SvelteMap<string, FailureState>();
61		let dispatchError = $state<string | null>(null);
62	
63		const client = createClient();
64		const terminalPhases = ['done', 'exited', 'stopped', 'failed', 'error', 'preserved'];
65		const failurePhases = ['failed', 'error'];
66		const subscriptions = new SvelteMap<string, () => void>();
67		const fallbackTimeouts = new SvelteMap<string, number>();
68		const pollingIntervals = new SvelteMap<string, number>();
69	
70		function fallbackDelayMs(): number {
71			if (typeof window === 'undefined') return 30_000;
72			const value = (window as typeof window & { __ddxPluginFallbackDelayMs?: number })
73				.__ddxPluginFallbackDelayMs;
74			return typeof value === 'number' && value >= 0 ? value : 30_000;
75		}
76	
77		function pollIntervalMs(): number {
78			if (typeof window === 'undefined') return 2_000;
79			const value = (window as typeof window & { __ddxPluginPollIntervalMs?: number })
80				.__ddxPluginPollIntervalMs;
81			return typeof value === 'number' && value > 0 ? value : 2_000;
82		}
83	
84		function formatDisk(bytes: number): string {
85			const units = ['B', 'KB', 'MB', 'GB'];
86			let value = bytes;
87			let index = 0;
88			while (value >= 1000 && index < units.length - 1) {
89				value /= 1000;
90				index += 1;
91			}
92			const display = value >= 10 || Number.isInteger(value) ? value.toFixed(0) : value.toFixed(1);
93			return `${display} ${units[index]}`;
94		}
95	
96		function statusLabel(status: string): string {
97			if (status === 'update-available') return 'Update available';
98			return status;
99		}
100	
101		function statusClass(status: string): string {
102			if (status === 'installed') {
103				return 'border-emerald-200 bg-emerald-50 text-emerald-700 dark:border-emerald-900 dark:bg-emerald-950 dark:text-emerald-300';
104			}
105			if (status === 'update-available') {
106				return 'border-amber-200 bg-amber-50 text-amber-800 dark:border-amber-900 dark:bg-amber-950 dark:text-amber-300';
107			}
108			return 'border-sky-200 bg-sky-50 text-sky-700 dark:border-sky-900 dark:bg-sky-950 dark:text-sky-300';
109		}
110	
111		function pluginByName(name: string): PluginInfo | null {
112			return plugins.find((plugin) => plugin.name === name) ?? null;
113		}
114	
115		function isBusy(name: string): boolean {
116			return dispatchingPlugins.has(name) || inFlightWorkers.has(name);
117		}
118	
119		function inFlightActionLabel(action: PluginAction): string {
120			return action === 'install' ? 'Installing...' : 'Updating...';
121		}
122	
123		function actionFailedLabel(action: PluginAction): string {
124			return action === 'install' ? 'Install failed' : 'Update failed';
125		}
126	
127		function isTerminalPhase(phase: string): boolean {
128			return terminalPhases.includes(phase);
129		}
130	
131		function isFailurePhase(phase: string): boolean {
132			return failurePhases.includes(phase);
133		}
134	
135		function setDispatching(name: string, value: boolean) {
136			if (value) dispatchingPlugins.add(name);
137			else dispatchingPlugins.delete(name);
138		}
139	
140		function clearFailure(name: string) {
141			workerFailures.delete(name);
142		}
143	
144		function openInstall(plugin: PluginInfo) {
145			if (isBusy(plugin.name)) return;
146			dispatchError = null;
147			installScope = 'global';
148			installingPlugin = plugin;
149			installOpen = true;
150		}
151	
152		function snapshotFor(plugin: PluginInfo): PluginSnapshot {
153			return {
154				status: plugin.status,
155				installedVersion: plugin.installedVersion
156			};
157		}
158	
159		function hasPluginChanged(name: string, previous: PluginSnapshot): boolean {
160			const current = pluginByName(name);
161			if (!current) return true;
162			return (
163				current.status !== previous.status || current.installedVersion !== previous.installedVersion
164			);
165		}
166	
167		function clearInFlight(name: string) {
168			subscriptions.get(name)?.();
169			subscriptions.delete(name);
170	
171			const timeout = fallbackTimeouts.get(name);
172			if (timeout != null) window.clearTimeout(timeout);
173			fallbackTimeouts.delete(name);
174	
175			const interval = pollingIntervals.get(name);
176			if (interval != null) window.clearInterval(interval);
177			pollingIntervals.delete(name);
178	
179			inFlightWorkers.delete(name);
180			inFlightActions.delete(name);
181			dispatchSnapshots.delete(name);
182		}
183	
184		async function refreshPlugins(): Promise<PluginInfo[]> {
185			const result = await client.request<PluginsListResult>(PLUGINS_LIST_QUERY);
186			plugins = result.pluginsList;
187			return result.pluginsList;
188		}
189	
190		function startFallbackPolling(name: string) {
191			if (pollingIntervals.has(name)) return;
192			const interval = window.setInterval(() => {
193				void pollPluginUntilChanged(name);
194			}, pollIntervalMs());
195			pollingIntervals.set(name, interval);
196			void pollPluginUntilChanged(name);
197		}
198	
199		async function pollPluginUntilChanged(name: string) {
200			if (!inFlightWorkers.has(name)) {
201				clearInFlight(name);
202				return;
203			}
204			const previous = dispatchSnapshots.get(name);
205			if (!previous) return;
206	
207			try {
208				await refreshPlugins();
209				if (hasPluginChanged(name, previous)) {
210					clearInFlight(name);
211				}
212			} catch (err) {
213				console.error('[ddx] plugin refresh poll failed:', err);
214			}
215		}
216	
217		function scheduleFallbackPolling(name: string) {
218			const timeout = window.setTimeout(() => {
219				fallbackTimeouts.delete(name);
220				if (inFlightWorkers.has(name)) startFallbackPolling(name);
221			}, fallbackDelayMs());
222			fallbackTimeouts.set(name, timeout);
223		}
224	
225		function subscribeToWorker(name: string, workerId: string, action: PluginAction) {
226			subscriptions.get(name)?.();
227			const dispose = subscribeWorkerProgress(
228				workerId,
229				(evt) => {
230					if (!isTerminalPhase(evt.phase)) return;
231					void handleWorkerTerminal(name, workerId, action, evt.phase);
232				},
233				(err) => {
234					console.error('[ddx] plugin workerProgress subscription error:', err);
235				}
236			);
237			subscriptions.set(name, dispose);
238		}
239	
240		async function handleWorkerTerminal(
241			name: string,
242			workerId: string,
243			action: PluginAction,
244			phase: string
245		) {
246			if (!inFlightWorkers.has(name)) return;
247			try {
248				await refreshPlugins();
249			} catch (err) {
250				console.error('[ddx] plugin refresh after worker terminal failed:', err);
251			}
252	
253			clearInFlight(name);
254			if (isFailurePhase(phase)) {
255				workerFailures.set(name, { workerId, action });
256			}
257		}
258	
259		async function dispatchPlugin(
260			name: string,
261			action: PluginAction,
262			scope: Scope = 'project'
263		): Promise<boolean> {
264			if (isBusy(name)) return false;
265			dispatchError = null;
266			clearFailure(name);
267			setDispatching(name, true);
268			try {
269				const result = await client.request<DispatchResult>(PLUGIN_DISPATCH_MUTATION, {
270					name,
271					action,
272					scope
273				});
274				const workerId = result.pluginDispatch.id;
275				const plugin = pluginByName(name);
276				inFlightWorkers.set(name, workerId);
277				inFlightActions.set(name, action);
278	
279				if (plugin) {
280					dispatchSnapshots.set(name, snapshotFor(plugin));
281				}
282	
283				subscribeToWorker(name, workerId, action);
284				scheduleFallbackPolling(name);
285				return true;
286			} catch (err) {
287				dispatchError = err instanceof Error ? err.message : 'Plugin action failed.';
288				return false;
289			} finally {
290				setDispatching(name, false);
291			}
292		}
293	
294		async function confirmInstall() {
295			if (!installingPlugin) return;
296			const dispatched = await dispatchPlugin(installingPlugin.name, 'install', installScope);
297			if (!dispatched) return;
298			installingPlugin = null;
299			installOpen = false;
300		}
301	
302		onDestroy(() => {
303			for (const dispose of subscriptions.values()) dispose();
304			for (const timeout of fallbackTimeouts.values()) window.clearTimeout(timeout);
305			for (const interval of pollingIntervals.values()) window.clearInterval(interval);
306		});
307	</script>
