422	func DispatchPluginAction(workingDir string, name string, action string) (string, error) {
423		pluginActionMu.Lock()
424		defer pluginActionMu.Unlock()
425	
426		state, err := registry.LoadState()
427		if err != nil {
428			return "", fmt.Errorf("loading plugin state: %w", err)
429		}
430	
431		switch action {
432		case "install":
433			if entry := state.FindInstalled(name); entry != nil && entry.VerifyFiles() {
434				return "installed", nil
435			}
436			entry, err := installRegistryPlugin(workingDir, state, name)
437			if err != nil {
438				return "", err
439			}
440			if entry != nil && entry.VerifyFiles() {
441				return "installed", nil
442			}
443			return "", fmt.Errorf("plugin %q install completed but recorded files are not present", name)
444		case "update":
445			installed := state.FindInstalled(name)
446			if installed == nil {
447				return "", fmt.Errorf("plugin %q is not installed", name)
448			}
449			pkg, err := registry.BuiltinRegistry().Find(name)
450			if err != nil {
451				return "", fmt.Errorf("plugin %q is not updateable from the built-in registry", name)
452			}
453			if installed.Version == pkg.Version && installed.VerifyFiles() {
454				return "installed", nil
455			}
456			entry, err := installRegistryPlugin(workingDir, state, name)
457			if err != nil {
458				return "", err
459			}
460			if entry != nil && entry.VerifyFiles() {
461				return "installed", nil
462			}
463			return "", fmt.Errorf("plugin %q update completed but recorded files are not present", name)
464		case "uninstall":
465			entry := state.FindInstalled(name)
466			if entry == nil {
467				return "", fmt.Errorf("plugin %q is not installed", name)
468			}
469			if err := registry.UninstallPackage(entry); err != nil {
470				return "", err
471			}
472			state.Remove(name)
473			if err := registry.SaveState(state); err != nil {
474				return "", fmt.Errorf("saving plugin state: %w", err)
475			}
476			return "uninstalled", nil
477		default:
478			return "", fmt.Errorf("unsupported plugin action %q", action)
479		}
480	}
481	
482	func installRegistryPlugin(workingDir string, state *registry.InstalledState, name string) (*registry.InstalledEntry, error) {
483		pkg, err := registry.BuiltinRegistry().Find(name)
484		if err != nil {
485			return nil, err
486		}
487	
488		origDir, _ := os.Getwd()
489		if workingDir != "" && origDir != workingDir {
490			if err := os.Chdir(workingDir); err != nil {
491				return nil, fmt.Errorf("entering project root: %w", err)
492			}
493			defer func() { _ = os.Chdir(origDir) }()
494		}
495	
496		entry, err := registry.InstallPackage(pkg)
497		if err != nil {
498			return nil, fmt.Errorf("installing plugin %q: %w", name, err)
499		}
500		state.AddOrUpdate(entry)
501		if err := registry.SaveState(state); err != nil {
502			return nil, fmt.Errorf("saving plugin state: %w", err)
503		}
504		return state.FindInstalled(name), nil
505	}
