507	func readComparisonRecords(workingDir string) ([]comparisonDispatchRecord, error) {
508		dir := filepath.Join(workingDir, ".ddx", "comparisons")
509		entries, err := os.ReadDir(dir)
510		if os.IsNotExist(err) {
511			return []comparisonDispatchRecord{}, nil
512		}
513		if err != nil {
514			return nil, err
515		}
516		records := make([]comparisonDispatchRecord, 0, len(entries))
517		for _, entry := range entries {
518			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
519				continue
520			}
521			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
522			if err != nil {
523				return nil, err
524			}
525			var record comparisonDispatchRecord
526			if err := json.Unmarshal(data, &record); err != nil {
527				return nil, fmt.Errorf("parsing comparison record %s: %w", entry.Name(), err)
528			}
529			if record.ID == "" {
530				continue
531			}
532			records = append(records, record)
533		}
534		sort.Slice(records, func(i, j int) bool {
535			if !records[i].CreatedAt.Equal(records[j].CreatedAt) {
536				return records[i].CreatedAt.After(records[j].CreatedAt)
537			}
538			return records[i].ID < records[j].ID
539		})
540		return records, nil
541	}
