556	func newDispatchID(prefix string, parts ...string) string {
557		segments := []string{slug(prefix)}
558		for _, part := range parts {
559			if s := slug(part); s != "" {
560				segments = append(segments, s)
561			}
562		}
563		segments = append(segments, randomHex(4))
564		return strings.Join(segments, "-")
565	}
566	
567	func randomHex(n int) string {
568		b := make([]byte, n)
569		if _, err := rand.Read(b); err != nil {
570			return time.Now().UTC().Format("20060102T150405.000000000")
571		}
572		return hex.EncodeToString(b)
573	}
