575	func pluginCatalog(workingDir string) ([]*PluginInfo, error) {
576		reg := registry.BuiltinRegistry()
577		state, err := registry.LoadState()
578		if err != nil {
579			return nil, err
580		}
581	
582		byName := map[string]*PluginInfo{}
583		installedByName := map[string]registry.InstalledEntry{}
584		for _, entry := range state.Installed {
585			installedByName[entry.Name] = entry
586		}
587	
588		for _, pkg := range reg.Packages {
589			info := pluginInfoFromPackage(pkg, workingDir, installedByName[pkg.Name])
590			byName[info.Name] = info
591		}
592		for _, entry := range state.Installed {
593			if _, ok := byName[entry.Name]; ok {
594				continue
595			}
596			info := pluginInfoFromInstalled(entry, workingDir)
597			byName[info.Name] = info
598		}
599	
600		out := make([]*PluginInfo, 0, len(byName))
601		for _, info := range byName {
602			out = append(out, info)
603		}
604		sort.Slice(out, func(i, j int) bool { return out[i].Name < out[j].Name })
605		return out, nil
606	}
