608	func pluginInfoFromPackage(pkg registry.Package, workingDir string, installed registry.InstalledEntry) *PluginInfo {
609		info := &PluginInfo{
610			Name:           pkg.Name,
611			Version:        pkg.Version,
612			Type:           string(pkg.Type),
613			Description:    pkg.Description,
614			Keywords:       append([]string(nil), pkg.Keywords...),
615			Status:         "available",
616			RegistrySource: pkg.Source,
617			Skills:         []string{},
618			Prompts:        []string{},
619			Templates:      []string{},
620		}
621		if installed.Name != "" {
622			info.InstalledVersion = strPtr(installed.Version)
623			info.Status = "installed"
624			if installed.Version != "" && installed.Version != pkg.Version {
625				info.Status = "update-available"
626			}
627		}
628		if manifest, err := json.Marshal(pkg); err == nil {
629			info.Manifest = strPtr(string(manifest))
630		}
631		enrichPluginInfoFromDisk(info, workingDir, pkg.Name, installed)
632		return info
633	}
