652	func enrichPluginInfoFromDisk(info *PluginInfo, workingDir string, name string, entry registry.InstalledEntry) {
653		for _, root := range pluginRootCandidates(workingDir, name, entry) {
654			if root == "" {
655				continue
656			}
657			if stat, err := os.Stat(root); err != nil || !stat.IsDir() {
658				continue
659			}
660			if info.DiskBytes == 0 {
661				info.DiskBytes = dirSize(root)
662			}
663			if pkg, _, err := registry.LoadPackageManifest(root); err == nil && pkg != nil {
664				if pkg.Version != "" {
665					info.Version = pkg.Version
666				}
667				if pkg.Description != "" {
668					info.Description = pkg.Description
669				}
670				if pkg.Type != "" {
671					info.Type = string(pkg.Type)
672				}
673				if pkg.Source != "" {
674					info.RegistrySource = pkg.Source
675				}
676				if len(pkg.Keywords) > 0 {
677					info.Keywords = append([]string(nil), pkg.Keywords...)
678				}
679				if manifest, err := json.Marshal(pkg); err == nil {
680					info.Manifest = strPtr(string(manifest))
681				}
682			}
683			info.Skills = uniqueStrings(append(info.Skills, scanNamedChildren(root, []string{"skills", ".agents/skills", ".claude/skills"}, "SKILL.md")...))
