722	func dirSize(root string) int {
723		var total int64
724		_ = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
725			if err != nil || d.IsDir() {
726				return nil
727			}
728			if info, err := d.Info(); err == nil {
729				total += info.Size()
730			}
731			return nil
732		})
733		const maxInt32 = int64(1<<31 - 1)
734		if total > maxInt32 {
735			return int(maxInt32)
736		}
737		return int(total)
738	}
