740	func scanNamedChildren(root string, relDirs []string, marker string) []string {
741		var out []string
742		for _, rel := range relDirs {
743			base := filepath.Join(root, filepath.FromSlash(rel))
744			entries, err := os.ReadDir(base)
745			if err != nil {
746				continue
747			}
748			for _, entry := range entries {
749				if strings.HasPrefix(entry.Name(), ".") {
750					continue
751				}
752				if marker != "" {
753					if !entry.IsDir() {
754						continue
755					}
756					if _, err := os.Stat(filepath.Join(base, entry.Name(), marker)); err != nil {
757						continue
758					}
759				}
760				out = append(out, entry.Name())
761			}
762		}
763		return out
764	}
