781	func (r *queryResolver) efficacySnapshot(since, until, projectID *string) (efficacySnapshot, error) {
782		projectRoot := r.WorkingDir
783		if projectID != nil && strings.TrimSpace(*projectID) != "" {
784			projectRoot = r.projectRoot(strings.TrimSpace(*projectID))
785		}
786		startedAfter, err := parseOptionalEfficacyTime("since", since)
787		if err != nil {
788			return efficacySnapshot{}, err
789		}
790		startedBefore, err := parseOptionalEfficacyTime("until", until)
791		if err != nil {
792			return efficacySnapshot{}, err
793		}
794		logDir := agent.SessionLogDirForWorkDir(projectRoot)
795		query := agent.SessionIndexQuery{
796			StartedAfter:  startedAfter,
797			StartedBefore: startedBefore,
798		}
799		cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore)
800		fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
801		if err != nil {
802			return efficacySnapshot{}, err
803		}
804		sessionEfficacyCache.Lock()
805		if sessionEfficacyCache.byQuery == nil {
806			sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
807		}
808		if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
809			sessionEfficacyCache.Unlock()
810			return cached.snapshot, nil
811		}
812		sessionEfficacyCache.Unlock()
813	
814		entries, err := agent.ReadSessionIndex(logDir, query)
815		if err != nil {
816			return efficacySnapshot{}, err
817		}
818		snap := buildSessionIndexEfficacySnapshot(entries)
819		sessionEfficacyCache.Lock()
820		sessionEfficacyCache.byQuery[cacheKey] = sessionEfficacyCacheEntry{fingerprint: fingerprint, snapshot: snap}
821		sessionEfficacyCache.Unlock()
822		return snap, nil
823	}
