825	func sessionEfficacyCacheKey(logDir string, startedAfter, startedBefore *time.Time) string {
826		return strings.Join([]string{logDir, timeKey(startedAfter), timeKey(startedBefore)}, "|")
827	}
828	
829	func timeKey(t *time.Time) string {
830		if t == nil {
831			return ""
832		}
833		return t.UTC().Format(time.RFC3339Nano)
834	}
835	
836	func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
837		files, err := agent.SessionIndexShardFiles(logDir, query)
838		if err != nil {
839			return "", err
840		}
841		parts := make([]string, 0, len(files))
842		for _, file := range files {
843			info, err := os.Stat(file)
844			if os.IsNotExist(err) {
845				continue
846			}
847			if err != nil {
848				return "", err
849			}
850			parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
851		}
852		return strings.Join(parts, "|"), nil
853	}
854	
855	func parseOptionalEfficacyTime(name string, raw *string) (*time.Time, error) {
856		if raw == nil || strings.TrimSpace(*raw) == "" {
857			return nil, nil
858		}
859		value := strings.TrimSpace(*raw)
860		for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
861			if parsed, err := time.Parse(layout, value); err == nil {
862				utc := parsed.UTC()
863				return &utc, nil
864			}
865		}
866		return nil, fmt.Errorf("%s must be RFC3339 or YYYY-MM-DD, got %q", name, value)
867	}
