884	func buildSessionIndexEfficacySnapshot(entries []agent.SessionIndexEntry) efficacySnapshot {
885		grouped := map[string][]sessionEfficacyAttempt{}
886		for _, entry := range entries {
887			attempt := efficacyAttemptFromSession(entry)
888			if attempt.RowKey == "" {
889				continue
890			}
891			grouped[attempt.RowKey] = append(grouped[attempt.RowKey], attempt)
892		}
893		rows := make([]*EfficacyRow, 0, len(grouped))
894		attemptDetails := map[string][]*EfficacyAttempt{}
895		for rowKey, group := range grouped {
896			sort.Slice(group, func(i, j int) bool { return group[i].CreatedAt.After(group[j].CreatedAt) })
897			attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
898			var inputTokens, outputTokens, durations []int
899			var costs []float64
900			var successes int
901			for _, attempt := range group {
902				if attempt.Outcome == "succeeded" {
903					successes++
904				}
905				inputTokens = append(inputTokens, attempt.InputTokens)
906				outputTokens = append(outputTokens, attempt.OutputTokens)
907				durations = append(durations, attempt.DurationMs)
908				if attempt.CostUsd != nil {
909					costs = append(costs, *attempt.CostUsd)
910				}
911				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
912					BeadID:            attempt.BeadID,
913					Outcome:           attempt.Outcome,
914					DurationMs:        attempt.DurationMs,
915					CostUsd:           attempt.CostUsd,
916					EvidenceBundleURL: attempt.EvidencePath,
917				})
918			}
919			parts := strings.Split(rowKey, "|")
920			row := &EfficacyRow{
921				RowKey:             rowKey,
922				Harness:            parts[0],
923				Provider:           parts[1],
924				Model:              parts[2],
925				Attempts:           len(group),
926				Successes:          successes,
927				SuccessRate:        float64(successes) / float64(len(group)),
928				MedianInputTokens:  medianInt(inputTokens),
929				MedianOutputTokens: medianInt(outputTokens),
930				MedianDurationMs:   medianInt(durations),
931				MedianCostUsd:      medianFloatPtr(costs),
932			}
933			if row.SuccessRate < efficacyWarningFloor {
934				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
935			}
936			rows = append(rows, row)
937		}
938		sort.Slice(rows, func(i, j int) bool {
939			if rows[i].SuccessRate != rows[j].SuccessRate {
940				return rows[i].SuccessRate > rows[j].SuccessRate
941			}
942			return rows[i].RowKey < rows[j].RowKey
943		})
944	
945		return efficacySnapshot{rows: rows, attempts: attemptDetails}
946	}
