948	func efficacyAttemptFromSession(entry agent.SessionIndexEntry) sessionEfficacyAttempt {
949		model := firstNonEmpty(entry.Model, "unknown")
950		provider := firstNonEmpty(entry.Provider, providerFromModel(model), entry.Harness, "unknown")
951		harness := firstNonEmpty(entry.Harness, provider, "unknown")
952		cost := efficacyCost(entry)
953		outcome := efficacyOutcome(entry)
954		return sessionEfficacyAttempt{
955			RowKey:       strings.Join([]string{harness, provider, model}, "|"),
956			BeadID:       entry.BeadID,
957			Outcome:      outcome,
958			Harness:      harness,
959			Provider:     provider,
960			Model:        model,
961			InputTokens:  entry.InputTokens,
962			OutputTokens: entry.OutputTokens,
963			DurationMs:   entry.DurationMS,
964			CostUsd:      cost,
965			EvidencePath: efficacyEvidencePath(entry),
966			CreatedAt:    entry.StartedAt,
967		}
968	}
