1027						title:   doc.Title,
1028						score:   score,
1029						sortKey: "document:" + doc.Path,
1030					})
1031				}
1032			}
1033		}
1034	
1035		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
1036		if beads, err := store.ReadAll(); err == nil {
1037			for _, b := range beads {
1038				if score, ok := paletteScore(query, b.ID, b.Title); ok {
1039					out = append(out, paletteMatch{kind: "bead", id: b.ID, title: b.Title, score: score, sortKey: "bead:" + b.ID})
1040				}
1041			}
1042		}
1043	
1044		for _, action := range []struct{ id, label string }{
1045			{"drain-queue", "Drain queue"},
1046			{"realign-specs", "Re-align specs"},
1047			{"run-checks", "Run checks"},
1048		} {
1049			if score, ok := paletteScore(query, action.id, action.label); ok {
1050				out = append(out, paletteMatch{kind: "action", id: action.id, title: action.label, score: score, sortKey: "action:" + action.id})
1051			}
1052		}
1053		for _, nav := range []struct{ route, title string }{
1054			{"/beads", "Beads"},
