1056			{"/graph", "Graph"},
1057			{"/workers", "Workers"},
1058			{"/personas", "Personas"},
1059			{"/plugins", "Plugins"},
1060			{"/efficacy", "Efficacy"},
1061		} {
1062			if score, ok := paletteScore(query, nav.route, nav.title); ok {
1063				out = append(out, paletteMatch{kind: "nav", id: nav.route, title: nav.title, score: score, sortKey: "nav:" + nav.route})
1064			}
1065		}
