1069	func paletteScore(query string, fields ...string) (int, bool) {
1070		q := strings.ToLower(strings.TrimSpace(query))
1071		if q == "" {
1072			return 0, false
1073		}
1074		terms := strings.Fields(q)
1075		best := 1000
1076		for _, field := range fields {
1077			f := strings.ToLower(field)
1078			if strings.HasPrefix(f, q) {
1079				best = min(best, 0)
1080				continue
1081			}
1082			for _, part := range strings.FieldsFunc(f, func(r rune) bool {
1083				return r == '/' || r == '-' || r == '_' || r == '.' || r == ' ' || r == ':'
1084			}) {
1085				if strings.HasPrefix(part, q) {
1086					best = min(best, 1)
1087				}
1088			}
1089			allTerms := true
1090			for _, term := range terms {
1091				if !strings.Contains(f, term) {
1092					allTerms = false
1093					break
1094				}
1095			}
1096			if allTerms {
1097				best = min(best, 2)
1098			}
1099		}
1100		if best == 1000 {
1101			return 0, false
1102		}
1103		return best, true
1104	}
