1133		seen := map[string]bool{}
1134		var out []string
1135		for _, value := range values {
1136			value = strings.TrimSpace(value)
1137			if value == "" || seen[value] {
1138				continue
1139			}
1140			seen[value] = true
1141			out = append(out, value)
1142		}
