88			}
89			pollInterval = d
90		}
91	
92		record, err := a.manager.StartExecuteLoop(ExecuteLoopWorkerSpec{
93			ProjectRoot:   projectRoot,
94			Harness:       req.Harness,
95			Model:         req.Model,
96			Profile:       req.Profile,
