111	async function mockWorkerProgress(page: import('@playwright/test').Page) {
112		const subscriptions = new Map<
113			string,
114			Array<{ id: string; ws: { send: (message: string) => void } }>
115		>();
116	
117		await page.routeWebSocket('**/graphql', (ws) => {
118			ws.onMessage((msg) => {
119				const parsed = JSON.parse(msg as string) as {
120					id?: string;
121					type: string;
122					payload?: { query?: string; variables?: { workerID?: string } };
123				};
124	
125				if (parsed.type === 'connection_init') {
126					ws.send(JSON.stringify({ type: 'connection_ack' }));
127					return;
128				}
129	
130				if (
131					parsed.type === 'subscribe' &&
132					parsed.id &&
133					parsed.payload?.query?.includes('workerProgress')
134				) {
135					const workerID = parsed.payload.variables?.workerID;
136					if (!workerID) return;
137					const existing = subscriptions.get(workerID) ?? [];
138					existing.push({ id: parsed.id, ws });
139					subscriptions.set(workerID, existing);
140				}
141			});
142		});
143	
144		return {
145			hasSubscription(workerID: string) {
146				return (subscriptions.get(workerID)?.length ?? 0) > 0;
147			},
148			send(workerID: string, phase: string) {
149				const entries = subscriptions.get(workerID) ?? [];
150				for (const entry of entries) {
151					entry.ws.send(
152						JSON.stringify({
153							id: entry.id,
154							type: 'next',
155							payload: {
156								data: {
157									workerProgress: {
158										eventID: `${workerID}-${phase}`,
159										workerID,
160										phase,
161										timestamp: '2026-04-22T12:00:00Z',
162										logLine: null,
163										beadID: null
164									}
165								}
166							}
167						})
168					);
169					entry.ws.send(JSON.stringify({ id: entry.id, type: 'complete' }));
170				}
171			}
172		};
173	}
