141	// testStateProvider is a StateProvider backed by real bead data read from a
142	// bead.Store at construction time. It holds snapshots loaded from disk and
143	// filters them in-process to satisfy resolver queries.
144	type testStateProvider struct {
145		node     ddxgraphql.NodeStateSnapshot
146		projects []*ddxgraphql.Project
147		beads    []ddxgraphql.BeadSnapshot
148	}
149	
150	func newTestStateProvider(workDir string, store *bead.Store) *testStateProvider {
151		now := time.Now()
152		projID := "proj-integration-" + filepath.Base(workDir)
153	
154		allBeads, _ := store.ReadAll()
155		snaps := make([]ddxgraphql.BeadSnapshot, 0, len(allBeads))
156		for _, b := range allBeads {
157			snaps = append(snaps, ddxgraphql.BeadSnapshot{
158				ProjectID: projID,
159				ID:        b.ID,
160				Title:     b.Title,
161				Status:    b.Status,
162				Priority:  b.Priority,
163				IssueType: b.IssueType,
164				Owner:     b.Owner,
165				CreatedAt: b.CreatedAt,
166				UpdatedAt: b.UpdatedAt,
167				Labels:    b.Labels,
168			})
169		}
170	
171		registeredAt := now.Add(-time.Hour).UTC().Format(time.RFC3339)
172		lastSeen := now.UTC().Format(time.RFC3339)
173		return &testStateProvider{
174			node: ddxgraphql.NodeStateSnapshot{
175				ID:        "node-integration-test",
176				Name:      "integration-test-node",
177				StartedAt: now.Add(-time.Hour),
178				LastSeen:  now,
179			},
180			projects: []*ddxgraphql.Project{
181				{
182					ID:           projID,
183					Name:         "integration-test-project",
184					Path:         workDir,
185					RegisteredAt: registeredAt,
186					LastSeen:     lastSeen,
187				},
188			},
189			beads: snaps,
190		}
191	}
