208	func (p *testStateProvider) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
209		var out []ddxgraphql.BeadSnapshot
210		for _, b := range p.beads {
211			if status != "" && b.Status != status {
212				continue
213			}
214			if label != "" {
215				found := false
216				for _, l := range b.Labels {
217					if l == label {
218						found = true
219						break
220					}
221				}
222				if !found {
223					continue
224				}
225			}
226			if projectID != "" && b.ProjectID != projectID {
227				continue
228			}
229			out = append(out, b)
230		}
231		return out
232	}
